const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.suitability_assessment_id) return { json: { _empty: true, error: 'suitability_assessment_id required' } };
return { json: { _authorized: true, suitability_assessment_id: body.suitability_assessment_id } };

const rows = $input.item.json;
const a = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!a || !a.id) return { json: { _not_found: true } };

const systemPrompt = [
  'You are the Crystallux AI Needs Analyst for the INSURANCE vertical (vertical_id=insurance).',
  'Product: ' + a.product_type,
  'Apply FSRA Ontario insurance regulation + Canadian Income Tax Act considerations.',
  '',
  'Output strictly JSON. Schema:',
  '{',
  '  "coverage_gaps":             [ { "description": "<text>", "severity": "low|medium|high" } ],',
  '  "recommended_coverage_cents": <integer, e.g. 50000000 = $500,000>,',
  '  "recommended_term_years":     <integer, 0 if not term-based>,',
  '  "risk_factors":              [ "<short label>" ],',
  '  "tax_considerations":        "<2-3 sentences for life products; null otherwise>",',
  '  "estate_planning_notes":     "<2-3 sentences if applicable; null otherwise>",',
  '  "reasoning":                 "<3-5 sentences explaining recommendation>"',
  '}',
  '',
  'Rules:',
  '- Coverage amounts must be PROPORTIONAL to client income & dependents (typical guideline: 5-10x annual income for term life with dependents).',
  '- Default to lower-coverage recommendation when income data is missing — flag the gap.',
  '- Term length default: term_life=20y for working-age with dependents; otherwise 10y.',
  '- For non-life products (auto/home/commercial) recommended_term_years=0.',
  '- If client_situation is sparse, RECOMMEND further data capture instead of guessing — set coverage_gaps[0].severity=high.'
].join('\n');

const userPayload = JSON.stringify({
  vertical_id: 'insurance',
  product_type: a.product_type,
  client_situation: a.client_situation || {},
  risk_tolerance: a.risk_tolerance || null
});

return { json: {
  assessment: a,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 1200,
    temperature: 0.2,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPayload } ]
  }
} };

const ctx = $('Build Claude Prompt').item.json;
const a = ctx.assessment;
const resp = $input.item.json || {};
let text = '';
try { text = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(text).replace(/```json|```/g, '').trim()); } catch (e) {}
if (!parsed) parsed = { coverage_gaps: [{ description: 'Needs analysis failed; flagging for human review.', severity: 'high' }], recommended_coverage_cents: 0, recommended_term_years: 0, risk_factors: ['ai_parse_failure'], tax_considerations: null, estate_planning_notes: null, reasoning: 'parse_failed' };
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

return { json: {
  patch: {
    needs_analysis: parsed,
    ai_recommended_coverage_amount: parseInt(parsed.recommended_coverage_cents) || 0,
    ai_recommended_term_years: parseInt(parsed.recommended_term_years) || 0,
    ai_reasoning: parsed.reasoning || null,
    updated_at: new Date().toISOString()
  },
  assessment_id: a.id,
  client_id: a.client_id,
  advisor_id: a.advisor_id,
  tokens: tokens
} };
